SELECT tag FROM product_tags
WHERE product_id = #{id}
ORDER BY tag

SELECT count(*) FROM products p
LEFT JOIN categories c ON p.category_id = c.id

    p.state_id = 'PUBLISHED'
    AND p.name LIKE #{name}
    AND p.brand = #{brand}
    AND p.category_id = #{categoryId}

SELECT p.id, p.name, p.description, p.short_description as "shortDescription", p.brand, p.category_id as "categoryId", c.name as "categoryName", p.slug, p.state_id as "stateId", p.base_price as "basePrice", p.base_price as "sellingPrice" FROM products p LEFT JOIN categories c ON p.category_id = c.id
p.state_id = 'PUBLISHED' AND p.name LIKE #{name} AND p.brand = #{brand} AND p.category_id = #{categoryId}
${orderby} ${pagination}

SELECT count(*) FROM products p
LEFT JOIN categories c ON p.category_id = c.id

    p.name LIKE #{name}
    AND p.brand = #{brand}
    AND p.category_id = #{categoryId}
    AND p.slug = #{slug}
    AND p.state_id = #{stateId}

SELECT p.id as "id", p.name as "name", p.description as "description", p.short_description as "shortDescription", p.brand as "brand", p.category_id as "categoryId", c.name as "categoryName", p.slug as "slug", p.state_id as "stateId", p.flow_id as "flowId", p.base_price as "basePrice", p.base_price as "sellingPrice", p.base_price as "mrp", p.hsn_code as "hsnCode", p.country_of_origin as "countryOfOrigin", p.weight_grams as "weightGrams", p.is_active as "isActive", p.meta_title as "metaTitle", p.meta_description as "metaDescription", p.created_by as "createdBy", p.created_time as "createdTime", p.last_modified_time as "lastModifiedTime" FROM products p LEFT JOIN categories c ON p.category_id = c.id
p.name LIKE CONCAT('%', #{name}, '%') AND p.brand = #{brand} AND p.category_id = #{categoryId} AND p.slug = #{slug} AND p.state_id = #{stateId} AND (p.name ILIKE CONCAT('%', #{q}, '%') OR p.brand ILIKE CONCAT('%', #{q}, '%'))
${orderby} ${pagination}
